#include<bits/stdc++.h>
using namespace std;

const int N = 1e5 + 1;
const long long INF = 1e18;

long long d[N];
vector<pair<int,int>> adj[N];
bool vis[N];


void dijkstra(int source, int n) {
    for(int i = 1; i <= n; i++) {
        d[i] = INF, vis[i] = false;
    }
    d[source] = 0;

    priority_queue<pair<long long, int>> pq;
    pq.push({0, source});

    while(pq.size() != 0) {
        pair<long long, int> node = pq.top();
        pq.pop();

        int v = node.second;
        long long distance = node.first;

        // If node is already visited, continue
        if(vis[v]) {
            continue;
        }

        vis[v] = 1;

        for(auto edge: adj[v]) {
            int u = edge.first;
            int weight = edge.second;

            // Update the distance of the vertex
            d[u] = min(d[u], d[v] + weight);

            // Store as negative because pq lists the elements in descending order
            pq.push({-d[u], u}); 
        }
    }      
}

