import java.util.*;

class main {
    static final int N = 200001;
    static final long INF = (long)1e18;
    static long[] d = new long[N];
    static List<Pair>[] adj = new ArrayList[N];
    static boolean[] vis = new boolean[N];

    static class Pair {
        int node;
        long weight;

        Pair(int node, long weight) {
            this.node = node;
            this.weight = weight;
        }
    }

    static void dijkstra(int source, int n) {
        for (int i = 1; i <= n; i++) {
            d[i] = INF;
            vis[i] = false;
        }
        d[source] = 0;

        PriorityQueue<Pair> pq = new PriorityQueue<>((a, b) -> Long.compare(a.weight, b.weight));
        pq.add(new Pair(source, 0));

        while (!pq.isEmpty()) {
            Pair node = pq.poll();

            int v = node.node;
            long distance = node.weight;

            // If node is already visited, continue
            if (vis[v]) {
                continue;
            }

            vis[v] = true;

            for (Pair edge : adj[v]) {
                int u = edge.node;
                long weight = edge.weight;

                // Update the distance of the vertex
                d[u] = Math.min(d[u], d[v] + weight);

                pq.add(new Pair(u, d[u]));
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int m = scanner.nextInt();

        for (int i = 1; i <= n; i++) {
            adj[i] = new ArrayList<>();
        }

        for (int i = 0; i < m; i++) {
            int a = scanner.nextInt();
            int b = scanner.nextInt();
            int w = scanner.nextInt();

            // Undirected edge
            adj[a].add(new Pair(b, w));
            adj[b].add(new Pair(a, w));
        }

        dijkstra(1, n);

        // Print the distance
        for (int i = 1; i <= n; i++) {
            if (d[i] == INF) {
                System.out.print("-1 ");
            } else {
                System.out.print(d[i] + " ");
            }
        }
    }
}
